import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [showGhost, setShowGhost] = useState(true);
  const [alerts, setAlerts] = useState([]);

  useEffect(() => {
    const ws = new WebSocket("ws://127.0.0.1:8000/ws/buses");

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        if (data.alert) {
          setAlerts((prev) => [...prev, data.alert]);
        }
        if (data.buses) setBuses(data.buses);
      } catch (err) {
        console.error("WS parse error:", err);
      }
    };

    ws.onopen = () => console.log("[WS] Connected");
    ws.onclose = () => console.log("[WS] Disconnected");

    return () => ws.close();
  }, []);

  const runningBuses = buses.filter((b) => b.status === "Running");
  const ghostBuses = buses.filter((b) => b.status !== "Running");

  const displayedBuses = showGhost
    ? [...runningBuses, ...ghostBuses]
    : runningBuses;

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Alerts */}
      <div
        style={{
          position: "absolute",
          top: 10,
          left: 10,
          background: "rgba(255,0,0,0.1)",
          padding: "8px 12px",
          borderRadius: "8px",
          zIndex: 1000,
          maxHeight: "150px",
          overflowY: "auto",
        }}
      >
        {alerts.map((alert, i) => (
          <div key={i}>{alert}</div>
        ))}
      </div>

      {/* Ghost bus toggle */}
      <button
        onClick={() => setShowGhost(!showGhost)}
        style={{
          position: "absolute",
          bottom: 10,
          left: 10,
          padding: "8px 12px",
          zIndex: 1000,
        }}
      >
        {showGhost ? "Hide Ghost Buses" : "Show Ghost Buses"}
      </button>

      {/* Map */}
      <MapContainer center={[40.7128, -74.006]} zoom={12} style={{ height: "100%", width: "100%" }}>
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {displayedBuses.map((bus, index) => (
          <CircleMarker
            key={`${bus.id}-${index}`}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={bus.status === "Running" ? "green" : "red"}
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Route:</strong> {bus.route} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong> {bus.speed?.toFixed(1)} mph <br />
                {bus.anomaly && <strong style={{ color: "red" }}>⚠ Anomaly detected!</strong>}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
